def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
        else:
            score = 0
            residual = capacity - item
            for _ in range(3):
                if residual <= 0:
                    score += 10
                else:
                    score += 1 / residual
                residual *= 0.5
            if capacity > 2 * item:
                score *= 0.9
            else:
                score *= 1.1
            if score > 100:
                priorities[i] = 100
            else:
                priorities[i] = score
    return priorities
